script:
frappe.ui.form.on('Quotation', {
  refresh(frm) {
    frm.set_df_property('cm_payment_on_delivery', 'read_only', 1);
  },
  cm_deposit_percent(frm) { _cm_recalc_payments(frm); },
  cm_survey_percent(frm)  { _cm_recalc_payments(frm); },
  grand_total(frm)        { _cm_recalc_payments(frm); },
});

function _cm_recalc_payments(frm) {
  const total = flt(frm.doc.grand_total);
  if (!total) return;
  const dep_pct = flt(frm.doc.cm_deposit_percent);
  const sur_pct = flt(frm.doc.cm_survey_percent);
  const prec = frappe.defaults.get_default('float_precision') || 2;
  const on_order   = flt(total * dep_pct / 100, prec);
  const on_survey  = flt(total * sur_pct / 100, prec);
  const on_delivery = flt(total - on_order - on_survey, prec);
  frm.set_value('cm_payment_on_order',   on_order);
  frm.set_value('cm_payment_on_survey',  on_survey);
  frm.set_value('cm_payment_on_delivery', on_delivery);
}

frappe.ui.form.on('Quotation', {
  refresh(frm)                   { _cm_render_totals(frm); },
  grand_total(frm)               { _cm_render_totals(frm); },
});

function _cm_render_totals(frm) {
  const f = frm.fields_dict['cm_totals_html'];
  if (!f) return;

  const net   = frm.doc.net_total || 0;
  const vat   = frm.doc.total_taxes_and_charges || 0;
  const total = frm.doc.grand_total || 0;
  const cur   = frm.doc.currency || 'EUR';
  const rate  = frm.doc.taxes && frm.doc.taxes.length ? Math.round(frm.doc.taxes[0].rate) : '';
  const vat_label = rate ? `VAT (${rate}%)` : 'VAT';
  const fmt = (v) => format_currency(v, cur, 2);

  $(f.wrapper).html(`
    <div style="max-width:320px;margin:8px 0 4px auto;border:1px solid #c8e6c9;border-radius:4px;overflow:hidden;font-size:12px">
      <div style="display:flex;justify-content:space-between;padding:5px 12px;border-bottom:1px solid #e8e8e8">
        <span style="color:#777">Sub Total (Ex VAT)</span>
        <span style="font-weight:600">${fmt(net)}</span>
      </div>
      <div style="display:flex;justify-content:space-between;padding:5px 12px;border-bottom:1px solid #e8e8e8">
        <span style="color:#777">${vat_label}</span>
        <span style="font-weight:600">${fmt(vat)}</span>
      </div>
      <div style="display:flex;justify-content:space-between;align-items:center;padding:7px 12px;background:#339966;color:#fff">
        <span style="font-weight:700;letter-spacing:1px;font-size:13px">TOTAL</span>
        <div style="text-align:right">
          <div style="font-size:15px;font-weight:700">${fmt(total)}</div>
          <div style="font-size:9px;opacity:0.85">Inc. VAT</div>
        </div>
      </div>
    </div>
  `);
}
